import{_ as n,C as s,o,c as l,E as r,w as i,a as t,a0 as c}from"./chunks/framework.CkNTPv-z.js";const _=JSON.parse('{"title":"France Legal Rights","description":"Legal rights for transgender people in France","frontmatter":{"layout":"doc","title":"France Legal Rights","description":"Legal rights for transgender people in France"},"headers":[],"relativePath":"europe/france/legal-rights.md","filePath":"europe/france/legal-rights.md","lastUpdated":null}'),d={name:"europe/france/legal-rights.md"};function h(g,e,p,m,u,f){const a=s("Badge");return o(),l("div",null,[r(a,{variant:"yellow"},{default:i(()=>[...e[0]||(e[0]=[t("Self-ID since 2022",-1)])]),_:1}),r(a,{variant:"green"},{default:i(()=>[...e[1]||(e[1]=[t("Hate Crime Protections",-1)])]),_:1}),e[2]||(e[2]=c('<h1 id="legal-rights-in-france" tabindex="-1">Legal Rights in France <a class="header-anchor" href="#legal-rights-in-france" aria-label="Permalink to &quot;Legal Rights in France&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>France adopted a self-declaration model for legal gender recognition in 2022, significantly simplifying the previous process. Adults can apply to the civil registry court (tribunal judiciaire) in their area. The application requires a simple declaration that their gender identity does not match their recorded sex. No medical diagnosis, surgery, or hormone therapy is required.</p><p>Processing time varies by court but is typically 1-3 months. The cost is minimal (court filing fee of approximately €20).</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>First name changes can be done through the same civil registry process as gender recognition, or independently. You submit a request to the local civil registry office (mairie) along with justification. There is no fee for name changes.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>France prohibits discrimination based on gender identity and gender expression in:</p><ul><li><strong>Employment</strong>: All aspects of employment</li><li><strong>Goods and services</strong>: Housing, healthcare, public services</li><li><strong>Education</strong>: All levels</li><li><strong>Media</strong>: Hate speech and incitement are illegal</li></ul><p>The Défenseur des Droits (Rights Defender) handles discrimination complaints.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Gender identity is recognised as an aggravating factor for hate crimes. Transphobic crimes carry enhanced penalties. France has a national hate crime reporting system, and specialised police units handle LGBTQ+ hate crimes.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://outrans.org/" target="_blank" rel="noreferrer">OUTrans</a> — Trans support and advocacy</li><li><a href="https://acceptess-t.com/" target="_blank" rel="noreferrer">Acceptess-T</a> — Trans healthcare and legal support</li><li><a href="https://defenseurdesdroits.fr/" target="_blank" rel="noreferrer">Défenseur des Droits</a> — File discrimination complaints</li></ul>',14))])}const y=n(d,[["render",h]]);export{_ as __pageData,y as default};
